import pathlib
import time
import textwrap
import shutil
import yaml
import json

from python_on_whales import docker

from Deadline.studio_landscapes.constants import *
from Deadline.studio_landscapes.utils import *

from dagster import (
    AssetIn,
    AssetExecutionContext,
    asset,
    Output,
    AssetMaterialization,
    MetadataValue,
)


@asset(
    group_name="Dagster",
    compute_kind="python",
    ins={
        "env_base": AssetIn(),
        "build_base_image": AssetIn(),
    },
)
def build_dagster(
        context: AssetExecutionContext,
        env_base: dict,
        build_base_image: str,
) -> str:
    """
    """

    docker_file = pathlib.Path(
        env_base["DOT_DOCKER"],
        "landscapes",
        env_base.get("LANDSCAPE", "default"),
        "Dockerfiles",
        context.asset_key.path[-1],
        "Dockerfile",
    )

    tags = [
        f"{env_base.get('IMAGE_PREFIX')}/{context.asset_key.path[-1]}:latest",
        # f"{env_base.get('IMAGE_PREFIX')}/{context.asset_key.path[-1]}:{str(time.time())}",
        f"{env_base.get('IMAGE_PREFIX')}/{context.asset_key.path[-1]}:{env_base.get('LANDSCAPE', str(time.time()))}",
    ]

    pip_packages: list = [
        "dagster-shared[dagster_dev] @ git+https://github.com/michimussato/dagster-shared.git@main",
        "deadline-dagster[dev] @ git+https://github.com/michimussato/deadline-dagster.git@main",
    ]

    pip_install_str: str = str()
    for pip_package in pip_packages:
        pip_install_str += "RUN python{PYTHON_MAJ}.{PYTHON_MIN} -m pip install --root-user-action=ignore '%s'\n" % pip_package

    # @formatter:off
    docker_file_str = textwrap.dedent("""
        # {auto_generated}
        FROM {parent_image} AS {image_name}
        LABEL authors="{AUTHOR}"
        
        {pip_install_str}
        
        WORKDIR {DAGSTER_ROOT}
        COPY ./payload/workspace.yaml .
        
        WORKDIR {DAGSTER_HOME}
        COPY ./payload/dagster.yaml .
        
        WORKDIR {DAGSTER_ROOT}
        
        ENTRYPOINT ["dagster", "dev"]
        CMD []
    """).format(
        pip_install_str=pip_install_str.format(
            **env_base,
        ),
        auto_generated=f"AUTO-GENERATED by Dagster Asset {context.asset_key.path[-1]}",
        image_name=context.asset_key.path[-1],
        parent_image=build_base_image,
        **env_base,
    )
    # @formatter:on

    shutil.rmtree(docker_file.parent, ignore_errors=True)

    docker_file.parent.mkdir(parents=True, exist_ok=True)

    with open(docker_file, "w") as fw:
        fw.write(docker_file_str)

    payload = docker_file.parent / "payload"
    payload.mkdir(parents=True, exist_ok=True)

    # workspace.yaml
    # Todo:
    #  - [ ] fix hardcoded path
    shutil.copy(
        src=pathlib.Path("~/git/repos/studio-landscapes/configs/dagster/config/workspace.yaml").expanduser(),
        dst=payload,
    )

    # dagster.yaml
    # Todo:
    #  - [ ] fix hardcoded path
    shutil.copy(
        src=pathlib.Path("~/git/repos/studio-landscapes/configs/dagster/config/materializations/dagster.yaml").expanduser(),
        dst=payload,
    )

    with open(docker_file, "r") as fr:
        docker_file_content = fr.read()

    stream = docker.build(
        context_path=docker_file.parent.as_posix(),
        cache=DOCKER_USE_CACHE,
        tags=tags,
        stream_logs=True,
    )

    log: str = ""

    for msg in stream:
        context.log.debug(msg)
        log += msg

    cmds_docker = compile_cmds(
        docker_file=docker_file,
        tag=tags[1],
    )

    yield Output(tags[1])

    yield AssetMaterialization(
        asset_key=context.asset_key,
        metadata={
            context.asset_key.path[-1]: MetadataValue.path(tags[1]),
            "docker_file": MetadataValue.md(f"```shell\n{docker_file_content}\n```"),
            **cmds_docker,
            "build_logs": MetadataValue.md(f"```shell\n{log}\n```"),
            "env_base": MetadataValue.json(env_base),
        },
    )


@asset(
    group_name="Dagster",
    compute_kind="python",
    ins={
        "env_base": AssetIn(),
        "build_dagster": AssetIn(),
    },
)
def compose_dagster(
        context: AssetExecutionContext,
        env_base: dict,
        build_dagster: str,
) -> dict:
    """
    """

    docker_dict = {
        "services": {
            "dagster": {
                "container_name": "dagster",
                "hostname": "dagster",
                "domainname": env_base.get("ROOT_DOMAIN"),
                "restart": "always",
                "image": build_dagster,
                "networks": [
                    "repository",
                    "mongodb",
                ],
                "environment": {
                    "DAGSTER_HOME": env_base.get('DAGSTER_HOME'),
                },
                "command": [
                    "--workspace",
                    env_base.get('DAGSTER_WORKSPACE'),
                    "--host",
                    env_base.get('DAGSTER_HOST'),
                    "--port",
                    env_base.get('DAGSTER_DEV_PORT_CONTAINER'),
                ],
                "volumes": [
                    f"{env_base.get('NFS_ENTRY_POINT')}:{env_base.get('NFS_ENTRY_POINT')}",
                    f"{env_base.get('NFS_ENTRY_POINT')}:{env_base.get('NFS_ENTRY_POINT_LNS')}",
                ],
                "ports": [
                    f"{env_base.get('DAGSTER_DEV_PORT_HOST')}:{env_base.get('DAGSTER_DEV_PORT_CONTAINER')}",
                ],
            },
        },
    }

    docker_yaml = yaml.dump(docker_dict)

    yield Output(docker_dict)

    yield AssetMaterialization(
        asset_key=context.asset_key,
        metadata={
            context.asset_key.path[-1]: MetadataValue.json(docker_dict),
            "docker_dict": MetadataValue.md(f"```json\n{json.dumps(docker_dict, indent=2)}\n```"),
            "docker_yaml": MetadataValue.md(f"```yaml\n{docker_yaml}\n```"),
            "env_base": MetadataValue.json(env_base),
        },
    )
